 1	import React, { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import DurationDropdown from '@kubevirt-utils/components/DurationOption/DurationDropdown';
 5	import DurationOption from '@kubevirt-utils/components/DurationOption/DurationOption';
 6	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import useKubevirtUserSettingsTopConsumerCards from '@kubevirt-utils/hooks/useKubevirtUserSettings/useKubevirtUserSettingsTopConsumerCards';
 9	import { Overview } from '@openshift-console/dynamic-plugin-sdk';
10	import { Card, CardBody, CardHeader, CardTitle, SelectOption } from '@patternfly/react-core';
11	
12	import { TOP_CONSUMERS_DURATION_KEY, TOP_CONSUMERS_NUM_ITEMS_KEY } from './utils/constants';
13	import TopConsumersGridRow from './utils/TopConsumersGridRow';
14	import { TOP_AMOUNT_SELECT_OPTIONS } from './utils/utils';
15	
16	import './TopConsumersTab.scss';
17	
18	const TopConsumersTab: FC = () => {
19	  const { t } = useKubevirtTranslation();
20	
21	  const [localStorageData, setLocalStorageData] = useKubevirtUserSettingsTopConsumerCards();
22	  const onNumItemsSelect = (value) => setLocalStorageData(TOP_CONSUMERS_NUM_ITEMS_KEY, value);
23	  const onDurationSelect = (value: string) =>
24	    setLocalStorageData(
25	      TOP_CONSUMERS_DURATION_KEY,
26	      DurationOption.fromDropdownLabel(value).toString(),
27	    );
28	
29	  return (
30	    <Overview>
31	      <Card data-test="kv-top-consumers-card">
32	        <CardHeader
33	          actions={{
34	            actions: (
35	              <>
36	                <Link to="/monitoring/dashboards/grafana-dashboard-kubevirt-top-consumers?period=4h">
37	                  {t('View virtualization dashboard')}
38	                </Link>
39	                <div className="kv-top-consumers-card__dropdown--duration">
40	                  <DurationDropdown
41	                    selectedDuration={localStorageData?.[TOP_CONSUMERS_DURATION_KEY]}
42	                    selectHandler={onDurationSelect}
43	                  />
44	                </div>
45	                <div className="kv-top-consumers-card__dropdown--num-items">
46	                  <FormPFSelect
47	                    onSelect={(e, value) => onNumItemsSelect(value)}
48	                    selected={localStorageData?.[TOP_CONSUMERS_NUM_ITEMS_KEY]}
49	                    toggleProps={{ id: 'kv-top-consumers-card-amount-select' }}
50	                  >
51	                    {TOP_AMOUNT_SELECT_OPTIONS.map((opt) => (
52	                      <SelectOption key={opt.key} value={opt.value}>
53	                        {opt.value}
54	                      </SelectOption>
55	                    ))}
56	                  </FormPFSelect>
57	                </div>
58	              </>
59	            ),
60	            className: 'co-overview-card__actions',
61	            hasNoOffset: false,
62	          }}
63	          className="kv-top-consumers-card__header"
64	        >
65	          <CardTitle>{t('Top consumers')} </CardTitle>
66	        </CardHeader>
67	        <CardBody className="kv-top-consumers-card__body">
68	          <TopConsumersGridRow
69	            localStorageData={localStorageData}
70	            rowNumber={1}
71	            setLocalStorageData={setLocalStorageData}
72	            topGrid
73	          />
74	          <TopConsumersGridRow
75	            localStorageData={localStorageData}
76	            rowNumber={2}
77	            setLocalStorageData={setLocalStorageData}
78	          />
79	        </CardBody>
80	      </Card>
81	    </Overview>
82	  );
83	};
84	
85	export default TopConsumersTab;

